from flask import Flask, render_template, request, redirect, url_for, sessionfrom flask_mysqldb import MySQLfrom werkzeug.security import generate_password_hash, check_password_hashapp = Flask(__name__)# 🔐 obligatoire pour sessionapp.secret_key = 'secret123'# =========================# CONFIGURATION DATABASE# =========================app.config['MYSQL_HOST'] = 'localhost'app.config['MYSQL_USER'] = 'root'app.config['MYSQL_PASSWORD'] = ''app.config['MYSQL_DB'] = 'dbtest'mysql = MySQL(app)# =========================# IMPORT DES MODULES (CRUD)# =========================from bus import bus_bp, init_busfrom chauffeur import chauffeur_bp, init_chauffeurfrom ligne import ligne_bp, init_lignefrom reservation import reservation_bp, init_reservation# =========================# INITIALISATION# =========================init_bus(mysql)init_chauffeur(mysql)init_ligne(mysql)init_reservation(mysql)# =========================# ENREGISTREMENT BLUEPRINTS# =========================app.register_blueprint(bus_bp)app.register_blueprint(chauffeur_bp)app.register_blueprint(ligne_bp)app.register_blueprint(reservation_bp)# =========================# PAGE ACCUEIL# =========================@app.route('/')def home():    return redirect('/login')# =========================# LOGIN# =========================@app.route('/login', methods=['GET', 'POST'])def login():    if request.method == 'POST':        email = request.form['email'].strip()        password = request.form['password'].strip()        cursor = mysql.connection.cursor()        cursor.execute("SELECT * FROM utilisateur WHERE email=%s", (email,))        user = cursor.fetchone()        if user and check_password_hash(user[3], password):            session['user_id'] = user[0]            session['role'] = user[4]            if user[4] == 'client':                return redirect(url_for('client_dashboard'))            elif user[4] == 'chauffeur':                return redirect(url_for('driver_dashboard'))            elif user[4] == 'admin':                return redirect(url_for('admin_dashboard'))        return "Email ou mot de passe incorrect ❌"    return render_template('login.html')# =========================# SIGNUP (INSCRIPTION)# =========================@app.route('/signup', methods=['GET', 'POST'])def signup():    if request.method == 'POST':        nom = request.form['nom'].strip()        email = request.form['email'].strip()        password = request.form['password'].strip()        role = request.form['role']        cursor = mysql.connection.cursor()        # Vérifier email existant        cursor.execute("SELECT * FROM users WHERE email=%s", (email,))        if cursor.fetchone():            return "Email déjà utilisé ❌"        hashed_password = generate_password_hash(password)        cursor.execute(            "INSERT INTO users (nom, email, password, role) VALUES (%s, %s, %s, %s)",            (nom, email, hashed_password, role)        )        mysql.connection.commit()        return redirect('/login')    return render_template('signup.html')# =========================# LOGOUT# =========================@app.route('/logout')def logout():    session.clear()    return redirect('/login')# =========================# DASHBOARDS# =========================@app.route('/client')def client_dashboard():    if 'role' not in session or session['role'] != 'client':        return redirect('/login')    return render_template('client_dashboard.html')@app.route('/driver')def driver_dashboard():    if 'role' not in session or session['role'] != 'chauffeur':        return redirect('/login')    return render_template('driver_dashboard.html')@app.route('/admin')def admin_dashboard():    if 'role' not in session or session['role'] != 'admin':        return redirect('/login')    return render_template('admin_dashboard.html')# =========================# LANCEMENT# =========================if __name__ == "__main__":    app.run(debug=True)